\displaystyle{\begin{aligned}
  \frac{{\frac{1}{x-2}+\frac{4}{x-2}}}{{3-\frac{1}{x+2}}} \amp = \frac{({\frac{1}{x-2}+\frac{4}{x-2}})\cdot{\left(x+2\right)\mathopen{}\left(x-2\right)}}{({3-\frac{1}{x+2}})\cdot{\left(x+2\right)\mathopen{}\left(x-2\right)}} \\
    \amp = \frac{{\frac{1}{x-2}\mathopen{}\left(x+2\right)\mathopen{}\left(x-2\right)+\frac{4}{x-2}\mathopen{}\left(x+2\right)\mathopen{}\left(x-2\right)}}{{3\mathopen{}\left(x+2\right)\mathopen{}\left(x-2\right)-\frac{1}{x+2}\mathopen{}\left(x+2\right)\mathopen{}\left(x-2\right)}} \\
    \amp = \frac{{x+2+4\mathopen{}\left(x+2\right)}}{{3\mathopen{}\left(x^{2}-4\right)-\left(x-2\right)}}, x \ne 2 \text{ and }  x \ne -2 \\
    \amp = \frac{{x+2+4x+8}}{{3x^{2}-12-x+2}}, x \ne 2 \text{ and }  x \ne -2 \\
    \amp = \frac{{5x+10}}{{3x^{2}-x-10}}, x \ne 2 \text{ and }  x \ne -2 \\
    \amp = {\frac{5\mathopen{}\left(x+2\right)}{\left(3x+5\right)\mathopen{}\left(x-2\right)}, x\ne -2}
\end{aligned}
    }
